window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2018>1","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : SURDS -RADICALS","question":"Simplify: &radic;108&nbsp; + &radic;125&nbsp; - &radic;75&nbsp;","images":[],"options":{"A":"&radic;3&nbsp; + 5&radic;5&nbsp;","B":"6&radic;3&nbsp; - 5&radic;5&nbsp;","C":"6&radic;3&nbsp; + &radic;2&nbsp;","D":"6&radic;3&nbsp; - &radic;2&nbsp;"},"answer":"A","explanation":"&radic;108&nbsp; + &radic;125&nbsp; - &radic;75&nbsp;  &radic;36 \u00d7 3&nbsp; + &radic;25 \u00d7 5&nbsp; - &radic;25 \u00d7 3&nbsp;  &radic;36&nbsp; \u00d7 &radic;3&nbsp; + &radic;25&nbsp; \u00d7 &radic;5&nbsp; - &radic;25&nbsp; \u00d7 &radic;3&nbsp;  6&radic;3&nbsp; + 5&radic;5&nbsp; - 5&radic;3&nbsp;  &radic;3&nbsp; + 5&radic;5&nbsp;","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>2","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Evaluate ( 641/2 + 1251/3)2","images":[],"options":{"A":"121","B":"144","C":"169","D":"196"},"answer":"C","explanation":"= (\u221a64 + 3\u221a125)2   = (8+5)2 = 132     = 169","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>3","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"Given that y varies inversely as the square of x. If x = 3 when y = 100, fin the equation connecting x and y.","images":[],"options":{"A":"yx2 = 300","B":"yx2 = 900","C":"y=100x9","D":"y = 900x2"},"answer":"B","explanation":"y\u03b11x2  y=kx2  yx2 = k ------ (1)  when x = 3; y = 100  Equation (1) becomes   100(3)2 = k  k = 900  from (1) yx2 = 900","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>4","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Find the value of x for which 32four = 22x.","images":[],"options":{"A":"three","B":"five","C":"six","D":"seven"},"answer":"C","explanation":"Given that:  32four = 22x  Express both sides in base 10  (3 \u00d7 41) + (2 \u00d7 40) = 2 \u00d7 x 1 + 2 \u00d7 x0  12 + 2 = 2x + 2  12 = 2x  x = 6","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>5","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify:214\u00d7312\u00f7438","images":[],"options":{"A":"5/9","B":"115","C":"114","D":"145"},"answer":"D","explanation":"214\u00d7312\u00f7438  94\u00d772\u00f7358  94\u00d772\u00d7835  6335=95=145","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2018>6","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"There are 250 boys and 150 girls in a school. If 60% of the boys and 40% of the girls play football, what percentage of the school play football?","images":[],"options":{"A":"40.0%","B":"42.2%","C":"50.0%","D":"52.5%"},"answer":"D","explanation":"Number of boys = 250  Number of girls = 150  Total number of students = 400  60% of the boys play football  60100\u00d7250=150students  40% of the girls play football  =40100\u00d7150=60students  Total number of students that play football  150 + 60 = 210 students  Percentage of the school that play football  =210400\u00d7100=52.5%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>7","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"If log10(6x - 4) - log102 = 1, solve for x.","images":[],"options":{"A":"2","B":"3","C":"4","D":"5"},"answer":"C","explanation":"log10(6x - 4) - log102 = 1  Recall: logba - logbc = logb a/c  log106x-42=1  Also recall:  logxa = b  xb = a  Equation (1) becomes  101=6x - 42  6x - 4 = 10 \u00d7 2  6x = 20 + 4  6x = 24  x = 4","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>8","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"If F = 9/5 C + 32, find C when F = 98.6.","images":[],"options":{"A":"30","B":"37","C":"39","D":"41"},"answer":"B","explanation":"Given: F=95C+32  When F = 98.6  98.6=95C+32  98.6-32=95C  66.6=95C  333 = 9C  C = 37","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2018>9","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"If y + 2x = 4 and y - 3x = -1, find the value of (x + y).","images":[],"options":{"A":"3","B":"2","C":"1","D":"-1"},"answer":"A","explanation":"Given: y + 2x = 4 ------- *  y - 3x = -1 ----------   From ; y = -1 + 3x  substitute for y = -1 + 3x in *  5x = 5, x = 1  Sub x = 1 into * , y + 2(1) = 4  y = 4 - 2 ; y = 2  (x+ y) = 1 + 2 = 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>10","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Ifx:y:z=2:3:4,evaluate9x + 3y6z - 2y","images":[],"options":{"A":"112","B":"2","C":"212","D":"3"},"answer":"A","explanation":"Given: x : y : z = 2 : 3 : 4  9x + 3y6z - 2y=9(2) + 3(3)6(4) - 2(3)=18 + 918=2718=1.5","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>11","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify:2 - 18m21 + 3m","images":[],"options":{"A":"2(1 + 3m)","B":"2(2 + 3m2)","C":"2(1 - 3m)","D":"2(1 - 3m2)"},"answer":"C","explanation":"Given:2-18m21+3m  Factorize the numerator  2(1-9m2)1+3m  From difference of two squares, i.e   a2 + b2 = (a - b)(a + b)  2(1-9m2)1+3m=2(1-3m)(1+3m)(1+3m)  = 2(1 - 3m)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>12","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"A curve is such that when y = 0, x = -2 or x = 3. Find the equation of the curve.","images":[],"options":{"A":"y = x2 - 5x - 6","B":"y = x2 + 5x - 6","C":"y = x2 + x - 6","D":"y = x2 - x - 6"},"answer":"D","explanation":"From the options given the curve is a curve of quadratic function.  Recall: For a quadratic function.  y = ax2 + bx + c  The points at which y = 0; and x = -2 or x = 3, tell us about the root of the equation.    To get a quadratic equation whose roots are given; we use:  y = x2 - (sum of roots)x + Product of roots  y = x2 - (-2 + 3)x + (-2)(+3)  y = x2 - (1)x - 6  y = x2 - x - 6","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>13","subject":"Mathematics","year":"2018","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The volume of a cylindrical tank, 10m high is 385m3. Find the diameter of the tank.  [Take \u03c0 = 22/7]","images":[],"options":{"A":"14m","B":"10m","C":"7m","D":"5m"},"answer":"C","explanation":"Recall: Vc = \u03c0r2h ----------- *  Vc = 385m3  h = 10m  From*  385 = 22/7 \u00d7 r2 \u00d7 10  385 \u00d7 7 = 220r2  r2=385 \u00d7 7220  r2 = 12.25  r = &radic;12.25&nbsp;  r = 3.5m  N.B: Diameter, D = 2 \u00d7 radius(r)  D = 2r = 2(3.5) = 7.0m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>14","subject":"Mathematics","year":"2018","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The surface area of a sphere is 792/7 cm2. Find, correct to the nearest whole number, its volume.  [ Take \u03c0 = 22/7 ]","images":[],"options":{"A":"113 cm3","B":"131 cm3","C":"311 cm3","D":"414 cm3"},"answer":"A","explanation":"SurfaceArea=7927cm2  Volume = Unknown  Recall: Surface Area of a sphere of radius r = 4\u03c0r2  7927=4\u00d7227\u00d7r2  792 = 88r2  r2 = 9  r = &radic;9&nbsp; = 3cm  Volume(V)ofasphere=43\u03c0r3  =43\u00d7227\u00d733  =4\u00d7227\u00d79=7927cm3  = 113.0 to the nearest whole number.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>15","subject":"Mathematics","year":"2018","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"A piece of thread of length 21.4cm is used to form a sector of a circle of radius 4.2cm on a piece of cloth. Calculate, correct to the nearest degree, the angle of the sector.  [ Take \u03c0 = 22/7 ]","images":[],"options":{"A":"170\u00b0","B":"177\u00b0","C":"182\u00b0","D":"192\u00b0"},"answer":"B","explanation":"Perimeter of the sector = 21.4cm  Recall: P = 2r + L  21.4 = 2(4.2) + L  21.4 = 8.4 + L  L = 13.0cm  Recall:L=\u03b8360\u00d72\u03c0r  13.0=\u03b8360\u00d7447\u00d74.2  13.0=\u03b8360\u00d726.4  \u03b8 = 177.0 to the nearest degrees.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>16","subject":"Mathematics","year":"2018","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"Inthediagram,whichofthefollowingratiosisequaltoPNPQ?","images":["data:image/png;base64,"],"options":{"A":"PNPR","B":"PMPQ","C":"PMPR","D":"PRPO"},"answer":"C","explanation":"From the diagram above, we can bring out two similar triangles    PNPQ=PMPR","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>17","subject":"Mathematics","year":"2018","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, PS and RS are tangents to the circle centre O, \u2220PSR = 70\u00b0, \u2220POR in and \u2220PQR = n. Find (m + n).","images":["data:image/png;base64,"],"options":{"A":"110\u00b0","B":"135\u00b0","C":"165\u00b0","D":"225\u00b0"},"answer":"C","explanation":"Given the diagram below:    Recall that there is a circle theorem that states that two tangents drawn to a circle from an external point are in equal length and substends equal angles at the centre.  Therefore, |PS| = |SR| ------------------- *  SO\u0302P = SOR --------------------- **  Another thing we need to know is that a tangent to a circle is perpendicular to the radius at the point of contact.  SR and PS are perpendicular to OR and OP respectively.  \u223490+m2+35=180\u00b0(sumofanglesin\u0394SOP)  125+m2=180  m2=55\u00b0  m = 110\u00b0  n=m2(angleatthecentreistwicethatsubstendedatotherpoints)  n = 55\u00b0;  (m + n) = 165\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>18","subject":"Mathematics","year":"2018","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Find the value of t in the diagram.","images":["data:image/png;base64,"],"options":{"A":"63\u00b0","B":"117\u00b0","C":"126\u00b0","D":"234\u00b0"},"answer":"C","explanation":"From the diagram given:  Consider ZYW (a straight line)  ZY\u0302X + XY\u0302W = 180\u00b0 (Sum of angles on a straight line)  117\u00b0 + XY\u0302W = 180\u00b0  XY\u0302W = 63\u00b0 ------ *  Now, the sector XYW becomes:    Recall: Angle substended at the centre is twice that subtended at other points on the circumference.  t = 2 \u00d7 63\u00b0  t = 126\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>19","subject":"Mathematics","year":"2018","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, PR is a tangent to the circle at Q, QT//RS, \u2220SQR = 35\u00b0 and \u2220RSQ = 50\u00b0. Find the value of \u2220QST.","images":["data:image/png;base64,"],"options":{"A":"40\u00b0","B":"65\u00b0","C":"85\u00b0","D":"95\u00b0"},"answer":"D","explanation":"Given the diagram below     QS\u0302R = TQ\u0302S (alternate angles)  Recall: The angle between a tangent to a circle and a chord drawn from the point of contact is equal to the angle in the alternate segment.   RQS = QTS = 35\u00b0  \u2234 In \u0394QTS   \u2234QTS + TQS + QST = 180\u00b0 (sum of angles in a \u0394)  35\u00b0 + 50 \u00b0 + QST = 180\u00b0   \u2234QST = 180\u00b0 - 85\u00b0   \u2234QST = 95\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>20","subject":"Mathematics","year":"2018","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"The angles of a polygon are x, 2x, 2x, (x + 30\u00b0), (x + 20\u00b0) and (x - 10\u00b0). Find the value of x.","images":[],"options":{"A":"45\u00b0","B":"84\u00b0","C":"85\u00b0","D":"95\u00b0"},"answer":"C","explanation":"We have 6 angles given, this indicates that we are dealing with a hexagon.  The sum of the interior angles in an n-sided polygon = 180(n - 2)  \u2234 The sum of the interior angles of a hexagon   = 180(6 - 2)  = 180(4) = 720  x + 2x + 2x + (x + 30) + (x + 20) + (x - 10) = 720  8x + 40 = 720  8x = 720 - 40  8x = 680  x = 85\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>21","subject":"Mathematics","year":"2018","type":"Objective","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"If M and N are the points (-3, 8) and (5, -7) respectively, find |MN|.","images":[],"options":{"A":"8 units","B":"11 units","C":"15 units","D":"17 units"},"answer":"D","explanation":"Given two points M(-3, 8) and N(5, -7)  |MN| = distance between the points given.  Recall: for two points A(x, y) and B(x2, y2), the distance between them is given as  D = &radic;(x2 - x1)2 + (y2 - y1)2&nbsp;  |MN| = &radic;(5 - - 3)2 + (-7 - 8)2&nbsp;  |MN| = &radic;82 + (-15)2&nbsp;  |MN| = &radic;64 + 225&nbsp;  |MN| = &radic;289&nbsp; = 17 units","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>22","subject":"Mathematics","year":"2018","type":"Objective","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"The equation of the line through the points (4, 2) and (-8, -2) is 3y = px + q, where p and q are constants. Find the value of p.","images":[],"options":{"A":"1","B":"2","C":"3","D":"9"},"answer":"A","explanation":"Given two points: (4, 2) and (-8, -2)  To get the equation of the line, we first find the slope  m=y2-y1x2-x1  m=-2-2-8-4=-4-12=13  Now express in the form y = mx + c -------- (1)  Pick any of the two points  (4, 2)  &nbspx y  (1) becomes   2=13(4)+c  2=43+c  2-43=c  6-43=c  c=23  (1) then becomes  y=13x+23  multiply through by 3  3y = x + 2 \u21d43y = Px + q  P = 1 and q = 2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>23","subject":"Mathematics","year":"2018","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"The angle of elevation of the top of a tree from a point 27m away and on the same horizontal ground as the foot of the tree is 30\u00b0. Find the height of the tree.","images":[],"options":{"A":"27m","B":"13.5&radic;3&nbsp;m","C":"13.5&radic;2&nbsp;m","D":"9&radic;3&nbsp;m"},"answer":"D","explanation":"tan30\u00b0=h27  1&radic;3&nbsp;=h27  h=27&radic;3&nbsp;  h = 9&radic;3&nbsp;m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>24","subject":"Mathematics","year":"2018","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"If tan x = 4/3 , 0\u00b0","images":[],"options":{"A":"1/10","B":"1/5","C":"5/12","D":"125"},"answer":"B","explanation":"Given: tan x = 4/3  0\u00b0  x is acute, i.e x is within the 1st quadrant.    sin x=45 cosx=35  sinx-cosx=45-35=15","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>25","subject":"Mathematics","year":"2018","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"Given that Y is 20m on a bearing of 300\u00b0 from X, how far south of Y is X?","images":[],"options":{"A":"10m","B":"15m","C":"25m","D":"30m"},"answer":"A","explanation":"sin30\u00b0=x20  x = 20sin30\u00b0   x = 20(0.5) = 10.0m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>26","subject":"Mathematics","year":"2018","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The mean of 1, 3, 5, 7 and x is 4. Find the value of x.","images":[],"options":{"A":"2","B":"4","C":"6","D":"8"},"answer":"B","explanation":"Given: the set of data - 1, 3, 5, 7 and x  x\u0304 = 4  Recall:  x\u0304=\u2211xn  4=1+3+5+7+x5  20 = 16 + x  x = 20 - 16  x = 4","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2018>27","subject":"Mathematics","year":"2018","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Find the median of 2, 1, 0, 3, 1, 1, 4, 0 1 and 2.","images":[],"options":{"A":"0.0","B":"0.5","C":"1.0","D":"1.5"},"answer":"C","explanation":"Given the set of data: 2, 1, 0, 3, 1, 1, 4, 0, 1 and 2  Arrange in order of increasing magnitude:  0, 0, 1, 1, 1, 1, 2, 2, 3, 4  There are 10 values gives  0 0 11 &nbsp &nbsp 11 &nbsp &nbsp &nbsp 22 34  Median=1+12=22=1.0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2018>28","subject":"Mathematics","year":"2018","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Number of goals1234567Number of teams3166423  The table shows the distribution of goals scored by 25 teams in a football competition. Use it to answer this question.    Calculate the probability that a team selected at random scored at most 3 goals.","images":[],"options":{"A":"325","B":"15","C":"625","D":"25"},"answer":"D","explanation":"From the table given:  Total number of teams = 25  The sum of the teams that scored at most 3 goals = 10  Pr(atmost3goals)=1025=25","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>29","subject":"Mathematics","year":"2018","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Number of goals1234567Number of teams3166423  The table shows the distribution of goals scored by 25 teams in a football competition. Use it to answer this question.  Find the probability that a team selected at random scored either 4 or 7 goals.","images":[],"options":{"A":"925","B":"1125","C":"35","D":"1825"},"answer":"A","explanation":"Probability that a team selected at random scored either 4 or 7 goals  P(4 goals) + P(7 goals)  625+325=925","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>30","subject":"Mathematics","year":"2018","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In the diagram, WXYZ is a rectangle with dimension 8cm by 6cm. P, Q, R and S are the midpoints of the sides of the rectangle as shown.  Use this information to answer this question    What type of quadrilateral is the shaded region?","images":["data:image/png;base64,"],"options":{"A":"Trapezium","B":"Prism","C":"Rectangle","D":"Rhombus"},"answer":"D","explanation":"The shaded region is a rhombus because it has all its side to be equal.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2018>31","subject":"Mathematics","year":"2018","type":"Objective","topic":"MENSURATION : AREAS","question":"In the diagram, WXYZ is a rectangle with dimension 8cm by 6cm. P, Q, R and S are the midpoints of the sides of the rectangle as shown.  Use this information to answer this question  Calculate the area of the part of the rectangle that is not shaded.","images":["data:image/png;base64,"],"options":{"A":"25 cm2","B":"24 cm2","C":"16 cm2","D":"12 cm2"},"answer":"B","explanation":"N.B: Total area of the rectangle  = Area of the shaded portion + Area of the unshaded portion     In the area that is not shaded, there are 4 right-angled triangles.  Totalarea=4\u00d712bh  =4\u00d712\u00d73\u00d74  = 24 cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>32","subject":"Mathematics","year":"2018","type":"Objective","topic":"MENSURATION : AREAS","question":"The total surface area of a hemisphere is 75 \u03c0 cm2. Find its radius.","images":[],"options":{"A":"5.0 cm","B":"7.0 cm","C":"8.5 cm","D":"12.0 cm"},"answer":"A","explanation":"Given: The total surface area = 75\u03c0cm2  Recall: Surface Area of a Hemisphere = 3\u03c0r2  3\u03c0r2 = 75\u03c0  3r2 = 75  r2 = 25  r = &radic;25&nbsp; = 5cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>33","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Findthevaluesofxforwhichx-5x(x-1)isundefined","images":[],"options":{"A":"0 or 5","B":"-5 or 5","C":"-1 or 5","D":"0 or 1"},"answer":"D","explanation":"Given, the rational function: x-5x(x-1)  When a rational function is undefined, it implies that its denominator equals zero  x(x - 1) = 0  x = 0 or x - 1 = 0  x = 0 or x = 1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>34","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Solve the equation 2x2 - x - 6 = 0.","images":[],"options":{"A":"x=-32or2","B":"x=-2or32","C":"x = -3 or 2","D":"x = 3 or -2"},"answer":"A","explanation":"Given: 2x2 - x - 6 = 0  2x2 - 4x + 3x - 6 = 0  2x(x - 2) + 3(x - 2) = 0  (2x + 3)(x - 2) = 0  x = -3/2 or x = 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>35","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Factorize completely the expression (x + 2)2 - (2x + 1)2","images":[],"options":{"A":"(3x + 2)(1 - x)","B":"(3x + 2)(2x + 1)","C":"3(x + 2)2","D":"3(x + 1)(1 - x)"},"answer":"D","explanation":"Given:  (x + 2)2 - (2x + 1)2  Recall: a2 - b2 = (a + b)(a - b) {Difference of two squares}  (x + 2 + 2x + 1)(x + 2 - 2x - 1) = (x + 2)2 - (2x + 1)2  (3x + 3)(1 - x)  3(x + 1)(1 - x)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>36","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"Find the nth term of the sequence 2 \u00d7 3, 4 \u00d7 6, 8 \u00d7 9, 16 \u00d7 12, . . .  .","images":[],"options":{"A":"2n \u00d7 3(n + 1)","B":"2n \u00d7 3n","C":"2n \u00d7 3n","D":"2n \u00d7 3n - 1"},"answer":"B","explanation":"Given: The sequence: 2 \u00d7 3, 4 \u00d7 6, 8 \u00d7 9, 16 \u00d7 12 . . .  From inspection,  Tn = 2n \u00d7 3n --------------- *    for the given sequence, the nth term is 2nx3n","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>37","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : MODULAR ARITHMETIC","question":"If 3x \u22614 (mod 5), find the least value of x.","images":[],"options":{"A":"1","B":"2","C":"3","D":"4"},"answer":"C","explanation":"Given: 3x = 4 (mod 5)  By inspection, the least value of x = 3  3 \u00d7 3 = 9  9 = 4 (mod 5).","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>38","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"The solution of x + 2 \u2265 2x + 1 is illustrated on the number line as","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"A","explanation":"x + 2 \u2265 2x + 1  -x \u2265 -1  x \u2264 1 -----------*  \"x less than or equal to 1\"","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2018>39","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : LOGICAL REASONING","question":"If p and q are two statements, under what condition would p \u2192 q be false?","images":[],"options":{"A":"If p is true and q is true","B":"If p is true and q is false","C":"If p is false and q is false","D":"If p is false and q is true"},"answer":"B","explanation":"When P is a true statement and Q is a false statement, it always implies that the combination of the two statements is false.  pqp\u2192qTTTTFFFTTFFT","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>40","subject":"Mathematics","year":"2018","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"The diagram shows a trapezium inscribed in a semi-circle. If O is the mid-point of WZ and |WX| = |XY| = |YZ|, calculate the value of m.","images":["data:image/png;base64,"],"options":{"A":"90\u00b0","B":"60\u00b0","C":"45\u00b0","D":"30\u00b0"},"answer":"B","explanation":"N.B X\u0305Y\u0305 is parallel to WZ  * All the 3 triangles within the parallelogram are isosceles   * Let us pick one of them to evaluate m.   |WX|  = |XY| = |YZ|  \u2218 (sum of angles on a striaght line)  1803=60\u2218  m + m = 2m (base angles of an isoscles triangle)   60 + 2m = 180 (sum of angles in a triangle)  2m = 180 - 60  m=1202  m = 60\u2218","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>41","subject":"Mathematics","year":"2018","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Find the inter-quartile range of 1, 3, 4, 5, 8, 9, 10, 11, 12, 14, 16.","images":[],"options":{"A":"6","B":"7","C":"8","D":"9"},"answer":"C","explanation":"Given: the set of data  1, 3, 4, 5,8, 9, 10, 11, 12, 14, 16  Inter-quartile range = Q3 - Q1  Q3=34\u00d7(n + 1)andQ1=14\u00d7(n + 1)  n = total frequency  n = 11  n + 1 = 12  Q3-Q1=(34\u00d712)-(14\u00d712)  =9th position-4th position  = 12 - 4    = 8","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>42","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : FINANCIAL ARITHMETIC","question":"Donations during the launching of a church project were sent in sealed envelopes. The table shows the distribution of the amount of money in the envelope.  No. of envelopes4720945312Amount (\u20a6)50002000100070050010050210  How much was the total donation?","images":[],"options":{"A":"\u20a626, 792.00","B":"\u20a626, 972.00","C":"\u20a662, 792.00","D":"\u20a662, 972.00"},"answer":"D","explanation":"From the table given, the total donation = (5000)4 + (2000)7 + (1000)20 + (700)9 + (500)4 + (100)5 + (50)3 + (2)1 + (10)2= 20,000 + 14,000 + 20,000 + 6300 + 2000 + 500 + 150 + 2 + 20= \u20a662, 972.00","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>43","subject":"Mathematics","year":"2018","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, PQ is a straight line, (m + n) =160\u00b0, (n - r) = 80\u00b0 and (m - r) = 40\u00b0. Find the ratio of m : n : r.","images":["data:image/png;base64,"],"options":{"A":"1 : 3 : 5","B":"3 : 5 : 1","C":"4 : 5 : 3","D":"5 : 6 : 7"},"answer":"D","explanation":"m+n = 110.......(1)  n+r = 130 .......(2)  m+r = 120......(3)  n = 130 - r......(4)  sub n = 130- r ......(1)  m + 130 - r ; m = r - 20 ,  sub m = r- 20 into eqn 3  r =  2 0 + r = 20 ; 2r = 140   r = 70   sub 70 into equation ......(2)  n+70 = 130 ; n = 60 ,  sub n= 60 into eqn......(1)  m + 60 = 110 , m = 50 ;   thus m:n:r = 50:60:70 = 5:6:7","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>44","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"If x : y = 1/4 : 3/8 and y : z = 1/3 : 4/9 , find x : z.","images":[],"options":{"A":"2 : 3","B":"3 : 4","C":"3 : 8","D":"1 : 2"},"answer":"D","explanation":"xy=14\u00f738  xy=14\u00d783  xy=23---------*    yz=13\u00f749  yz=13\u00d794  yz=34----------**  x:z=xz=xy\u00d7yz=23\u00d734=24=12","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2018>45","subject":"Mathematics","year":"2018","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Find the mean deviation of 20, 30, 25, 40, 35, 50, 45, 40, 20 and 45.","images":[],"options":{"A":"8","B":"9","C":"10","D":"12"},"answer":"B","explanation":"Given: The set of data  20, 30, 25, 40, 35, 50, 45, 40, 20 and 45  Recall: MeanDeviation=\u2211f(x-x\u0305)\u2211f-------*  x20253035404550f2111221  x\u0305=\u2211fx\u2211f=(20\u00d72)+(25\u00d71)+(30\u00d71)+(35\u00d71)+(40\u00d72)+(45\u00d72)+(50\u00d71)2+1+1+1+2+2+1  x\u0305=40+25+30+35+80+90+5010  x\u0305=65+65+22010=35010=35  M.D=2(20-35)+1(25-35)+1(30-35)+1(35-35)+2(40-35)+2(45-35)+1(50-35)10  M.D=2(15)+1(10)+1(5)+1(0)+2(5)+2(10)+1(15)10  M.D=9010=9.0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>46","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"M and N are two subsets of the universal set (U). If n(U) = 48, n(M) = 20, n(N) = 30 and n(M \u222a N) = 40, find n(M \u2229 N)'.","images":[],"options":{"A":"18","B":"20","C":"30","D":"38"},"answer":"D","explanation":"Given:  n(U) = 48  n(M) = 20  n(N) = 30  n(M \u222a N) = 40  n(M \u2229N) = ?      From the Venn diagram above,  (M \u2229 N)c = (M - M\u2229N) + (N - M \u2229 N) + (M \u222a N)c  OR  (M \u2229 N)c = (U - M \u2229 N)  We can apply either of the two.  N.B: n(U) = n(M \u222a N) + n(M \u222a N)c ------------- *  n(M \u222a N) = n(M) + n(N) - n(M \u2229 N) --------    48 = 40 + n(M \u222a N)c {From *}  n(M \u222a N)c = 8    Also, 40 = 30 + 20 - n(M \u2229 N) {From }  40 = 50 - n(M \u2229 N)  -10 = -n(M \u2229 N)  n(M \u2229 N) = 10    Apply one of the two equations above  n(M \u2229 N)c = n(U) - n(M \u2229 N)  n(M \u2229 N)c = 48 - 10 = 38","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2018>47","subject":"Mathematics","year":"2018","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Express 0.612 in the form x/y, where x and y are integers and y \u2260 0.","images":[],"options":{"A":"153/250","B":"68/111","C":"61/100","D":"21/33"},"answer":"A","explanation":"Given:  The three \"dots\" depicts a recurrent decimal. We convert a recurrent decimal into fraction using the approach below.  0.612 = 612/1000 = 153/250","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2018>48","subject":"Mathematics","year":"2018","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, PQ/RS. Find x in terms of y and z.","images":["data:image/png;base64,"],"options":{"A":"x = 240\u00b0 - y - z","B":"x = 180\u00b0 - y - z","C":"x = 360\u00b0 + y - z","D":"x = 360\u00b0 - y - z"},"answer":"D","explanation":"From the diagram,  x = 180 - y + 180 - z  x = 360 - y - z ------- *","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>49","subject":"Mathematics","year":"2018","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"The diagonals of a rhombus WXYZ intersect at M. If |MW| = 5cm and |MX| = 12cm, calculate its perimeter.","images":[],"options":{"A":"42 cm","B":"48 cm","C":"52 cm","D":"60 cm"},"answer":"C","explanation":"\u0394 MWX is right angled  From pythagora's theorem  |WX|2 = 52 + 122  |WX|2 = 25 + 144  |WX|2 = 169  |WX| = 13cm  |WX| is the length of one side of the parallelogram  The perimeter = 4(13) = 52cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2018>50","subject":"Mathematics","year":"2018","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The graphs of y = x2 and y = x intersect at which of these points?","images":[],"options":{"A":"(0, 0), (1, 1)","B":"(0,0), (0, 1)","C":"(1, 0), (0, 0)","D":"(0, 0), (0, 0)"},"answer":"A","explanation":"Given:  y = x2 -------------*  y = x ---------------**    Equate y to y  x2 - x = 0  x(x - 1) = 0  x = 0 or x = 1  x1 = 0 and x2 = 1  y1 = 0 and y2 = 1  (x1,y1) = (0, 0)  and (x2, y2) = (1, 1)","marks":"1","difficulty":"3"}];